package cli

import (
	"errors"
	"fmt"
	"path/filepath"
	"time"

	"github.com/spf13/cobra"

	"github.com/agent-sync/agent-sync/internal/engine"
	"github.com/agent-sync/agent-sync/internal/fsroot"
	"github.com/agent-sync/agent-sync/internal/report"
)

// hookSkippedMarker records that a git-hook-driven sync yielded to an
// in-progress manual sync (so it never breaks `git pull`).
const hookSkippedMarker = ".agent-sync/state/hook-skipped"

func newSyncCommand(deps RootDeps) *cobra.Command {
	var (
		bestEffort      bool
		adoptPrefixes   []string
		targetFilter    []string
		expectDeletions int
		postMerge       bool
	)

	cmd := &cobra.Command{
		Use:   "sync",
		Short: "Sync target tools from the canonical manifest",
		Long: "Materialize the canonical source, run each target's adapter, and " +
			"atomically write the resulting configuration into the workspace.",
		SilenceUsage:  true,
		SilenceErrors: true,
		RunE: func(cmd *cobra.Command, _ []string) error {
			rc, err := mustRuntime(cmd)
			if err != nil {
				return err
			}
			now := deps.now()()

			prep, err := prepareEngine(cmd.Context(), rc, now)
			if err != nil {
				return fmt.Errorf("sync: %w", err)
			}
			defer prep.Close()

			req := prep.Request
			req.Options.AdoptPrefixes = adoptPrefixes
			req.Options.TargetsFilter = targetFilter
			if bestEffort {
				req.Options.Mode = report.ModeBestEffort
			} else {
				req.Options.Mode = report.ModeAtomic
			}
			if cmd.Flags().Changed("expect-deletions") {
				req.Options.ExpectDeletions = &expectDeletions
			}

			root := prep.Root
			summary, err := engine.Sync(cmd.Context(), req)
			if err != nil {
				return fmt.Errorf("sync: %w", err)
			}

			// Post-merge hook mode: if a target was blocked by an in-progress
			// sync's lock, write the skip marker and exit 0 so `git pull` is
			// never broken (plan U3 / AGENTS invariant #3 spirit).
			if postMerge && anyBlocked(summary) {
				if werr := writeHookSkipped(root, now); werr != nil {
					// Still exit 0 so `git pull` is never broken, but log it: the
					// marker is the only breadcrumb explaining the skip, so a
					// silent write failure makes diagnosis hard.
					rc.Logger.Warn("sync: failed to write hook-skipped marker", "err", werr)
				}
				return nil
			}

			if err := renderSummary(cmd, rc.Access, summary); err != nil {
				return err
			}
			if summary.Outcome.ExitCode != 0 {
				return &exitError{code: summary.Outcome.ExitCode, err: errors.New("sync reported failures")}
			}
			return nil
		},
	}

	cmd.Flags().BoolVar(&bestEffort, "best-effort", false, "continue past a failing target instead of aborting the run")
	cmd.Flags().StringArrayVar(&adoptPrefixes, "adopt-prefix", nil, "adopt pre-existing unmanaged content under this reserved prefix")
	cmd.Flags().StringArrayVar(&targetFilter, "target", nil, "restrict the sync to these target names (repeatable)")
	cmd.Flags().IntVar(&expectDeletions, "expect-deletions", 0, "abort unless exactly this many files would be deleted")
	cmd.Flags().BoolVar(&postMerge, "post-merge", false, "git-hook mode: yield to an in-progress sync and exit 0")
	return cmd
}

func anyBlocked(s report.Summary) bool {
	for _, t := range s.Targets {
		if t.Status == report.StatusBlocked {
			return true
		}
	}
	return false
}

func writeHookSkipped(root *fsroot.Root, now time.Time) error {
	if err := root.Inner().MkdirAll(filepath.Dir(hookSkippedMarker), 0o755); err != nil {
		return err
	}
	return root.StagedWrite(hookSkippedMarker, []byte(now.UTC().Format(time.RFC3339)+"\n"), 0o644)
}

// renderSummary writes the report to stdout as text or JSON per the
// resolved Access; logs and banners go to stderr (the logger), data to
// stdout.
func renderSummary(cmd *cobra.Command, access Access, summary report.Summary) error {
	if access.Output == OutputJSON {
		data, err := report.MarshalJSON(summary)
		if err != nil {
			return fmt.Errorf("sync: marshal json: %w", err)
		}
		_, err = fmt.Fprintln(cmd.OutOrStdout(), string(data))
		return err
	}
	_, err := fmt.Fprint(cmd.OutOrStdout(), report.RenderText(summary))
	return err
}

package cli

import (
	"context"
	"errors"
	"fmt"
	"time"

	"github.com/agent-sync/agent-sync/internal/cache"
	"github.com/agent-sync/agent-sync/internal/fsroot"
	"github.com/agent-sync/agent-sync/internal/git"
	"github.com/agent-sync/agent-sync/internal/ir"
	"github.com/agent-sync/agent-sync/internal/manifest"
	"github.com/agent-sync/agent-sync/internal/trust"
	"github.com/agent-sync/agent-sync/internal/worktree"
)

// ErrFloatingLocalUnsupported is returned when a local_path canonical
// source is not pinned. Resolving a moving local HEAD is deferred; pin
// the manifest (invariant #4: pinning is default) to sync from a local
// path.
var ErrFloatingLocalUnsupported = errors.New("cli: floating local_path sync is not yet supported; pin the manifest with a commit")

// materialized is the decoded canonical source ready to hand to the engine.
type materialized struct {
	Nodes  []ir.Node
	Skills map[string]ir.Skill
	Commit string // the resolved SHA, stamped into the report + staging
	// Warnings are non-fatal decode signals (from ir.Decode and
	// ir.SkillsByID) — e.g. a missing AGENTS.md or an unreadable skill
	// asset. The caller surfaces them so they are not silently dropped.
	Warnings []ir.Warning
}

// materializeOptions controls network posture and supplies the workspace root
// needed by the in-repo (local_dir) source kind.
type materializeOptions struct {
	Offline bool
	Now     time.Time
	// Root is the opened workspace root, consumed only by the local_dir source
	// kind (it reads the working tree). prepareEngine always supplies it; the
	// url/local_path paths ignore it. The nil check in materializeLocalDir is a
	// defensive guard for direct callers, not a state setup.go produces.
	Root *fsroot.Root
}

// materialize turns a loaded manifest into decoded IR. It dispatches on
// canonical source kind:
//   - local_dir: read directly from the working tree (no git, no network, no
//     trust, no pin) — see materializeLocalDir.
//   - local_path: open a local git clone directly (no network).
//   - url: canonicalize -> cache resolve -> git materialize, with the trust
//     gate enforced against the resolved SHA.
//
// The git-backed kinds require a pinned commit in v1; the local_dir kind is
// unpinned by nature.
func materialize(ctx context.Context, m *manifest.Manifest, opts materializeOptions) (materialized, error) {
	switch {
	case m.Canonical.LocalDir != "":
		return materializeLocalDir(m, opts)
	case m.Canonical.LocalPath != "":
		return materializeLocal(m)
	case m.Canonical.URL != "":
		return materializeURL(ctx, m, opts)
	default:
		return materialized{}, errors.New("cli: manifest has no canonical source (url, local_path, or local_dir)")
	}
}

// materializeLocalDir reads an in-repo working-tree source. It deliberately
// skips git materialization, the trust (TOFU) gate, and the offline-strict
// SHA requirement: a working-tree source touches no network and has no commit
// to pin or trust. The empty ref flows to the engine as a zero-SHA placeholder.
func materializeLocalDir(m *manifest.Manifest, opts materializeOptions) (materialized, error) {
	if opts.Root == nil {
		return materialized{}, errors.New("cli: local_dir source requires an open workspace root")
	}
	reader, err := worktree.NewReader(opts.Root, m.Canonical.LocalDir)
	if err != nil {
		return materialized{}, fmt.Errorf("cli: local_dir source: %w", err)
	}
	return decodeAt(reader, "")
}

func materializeLocal(m *manifest.Manifest) (materialized, error) {
	if m.Canonical.Commit == "" {
		return materialized{}, ErrFloatingLocalUnsupported
	}
	repo, err := git.Open(m.Canonical.LocalPath)
	if err != nil {
		return materialized{}, fmt.Errorf("cli: open local canonical %q: %w", m.Canonical.LocalPath, err)
	}
	defer func() { _ = repo.Close() }()
	return decodeAt(repo, m.Canonical.Commit)
}

func materializeURL(ctx context.Context, m *manifest.Manifest, opts materializeOptions) (materialized, error) {
	canonical, err := cache.Canonicalize(m.Canonical.URL)
	if err != nil {
		return materialized{}, fmt.Errorf("cli: canonicalize %q: %w", m.Canonical.URL, err)
	}
	loc, err := cache.Resolve(canonical, cache.ResolveOptions{Override: m.Cache.Override})
	if err != nil {
		return materialized{}, fmt.Errorf("cli: resolve cache: %w", err)
	}
	res, err := git.Materialize(ctx, git.Input{
		CanonicalURL: canonical,
		Cache:        loc,
		PinnedSHA:    m.Canonical.Commit,
		Ref:          m.Canonical.Ref,
		Floating:     m.Canonical.Commit == "",
		Offline:      opts.Offline,
	})
	if err != nil {
		return materialized{}, fmt.Errorf("cli: materialize %q: %w", canonical, err)
	}

	// Trust gate. For a pinned manifest, ManifestTrustedSHA is
	// authoritative (trust.Decide check #2): a matching resolved SHA
	// proceeds, a mismatch fails closed. Full user-history (TOFU) handling
	// for unpinned sources is deferred to the init wizard (U6).
	dec, derr := trust.Decide(trust.DecideInput{
		URL:                canonical,
		ResolvedSHA:        res.ResolvedSHA,
		ManifestTrustedSHA: m.TrustedSHA,
		Now:                opts.Now,
	})
	if derr != nil {
		return materialized{}, &exitError{code: trust.ExitCodeFor(derr), err: fmt.Errorf("cli: trust: %w", derr)}
	}
	_ = dec // pinned-path decision carries no further action

	repo, err := git.Open(res.LocalPath)
	if err != nil {
		return materialized{}, fmt.Errorf("cli: open materialized repo: %w", err)
	}
	defer func() { _ = repo.Close() }()
	return decodeAt(repo, res.ResolvedSHA)
}

// decodeAt decodes any SourceTree at ref. ref is a 40-hex commit SHA for
// git-backed sources and the empty string for the working-tree source (which
// has no commit); an empty ref flows through to the engine's zero-SHA
// placeholder.
func decodeAt(src ir.SourceTree, ref string) (materialized, error) {
	at := ref
	if at == "" {
		at = "working tree"
	}
	nodes, decodeWarnings, err := ir.Decode(src, ref, ir.DecodeOptions{})
	if err != nil {
		return materialized{}, fmt.Errorf("cli: decode IR at %s: %w", at, err)
	}
	skills, skillWarnings := ir.SkillsByID(nodes, src, ref)
	warnings := append(append([]ir.Warning(nil), decodeWarnings...), skillWarnings...)
	return materialized{Nodes: nodes, Skills: skills, Commit: ref, Warnings: warnings}, nil
}

package cli

import (
	"context"
	"errors"
	"fmt"
	"time"

	"github.com/agent-sync/agent-sync/internal/adapter"
	claudeadapter "github.com/agent-sync/agent-sync/internal/adapter/bundled/claude"
	codexadapter "github.com/agent-sync/agent-sync/internal/adapter/bundled/codex"
	cursoradapter "github.com/agent-sync/agent-sync/internal/adapter/bundled/cursor"
	"github.com/agent-sync/agent-sync/internal/engine"
	"github.com/agent-sync/agent-sync/internal/fsroot"
	"github.com/agent-sync/agent-sync/internal/manifest"
	"github.com/agent-sync/agent-sync/internal/workspace"
)

// bundledAdapters returns the compiled-in adapter set. Centralized so
// every command discovers the same adapters.
func bundledAdapters() []*adapter.BundledAdapter {
	return []*adapter.BundledAdapter{
		claudeadapter.Bundled(),
		cursoradapter.Bundled(),
		codexadapter.Bundled(),
	}
}

// prepared bundles the per-invocation engine inputs shared by sync and
// validate: an opened workspace root (the caller must Close it), the
// loaded manifest, and a fully-built engine.Request. Close releases the
// root.
type prepared struct {
	Workspace *workspace.Workspace
	Manifest  *manifest.Manifest
	Root      *fsroot.Root
	Request   engine.Request
	Close     func()
}

// prepareEngine performs the shared setup both sync and validate need:
// locate the workspace, load the manifest, open the root, materialize the
// canonical IR, discover adapters, and assemble an engine.Request. Per-run
// engine.Options (mode, adopt, expect-deletions) are layered on by the
// caller via the returned Request.Options.
func prepareEngine(ctx context.Context, rc *runtimeContext, now time.Time) (prepared, error) {
	if rc == nil {
		return prepared{}, errors.New("cli: prepareEngine called with nil runtime context")
	}
	flags := rc.Flags
	ws, err := workspace.Find(flags.Workspace, workspace.Options{Workspace: flags.Workspace})
	if err != nil {
		return prepared{}, fmt.Errorf("locate workspace: %w", err)
	}
	m, err := manifest.LoadFile(ws.ManifestPath, manifest.LoadOptions{NonInteractive: rc.Access.NonInteractive})
	if err != nil {
		return prepared{}, fmt.Errorf("load manifest: %w", err)
	}
	root, err := fsroot.OpenWorkspaceRoot(ws.Root)
	if err != nil {
		return prepared{}, fmt.Errorf("open workspace root: %w", err)
	}

	mat, err := materialize(ctx, m, materializeOptions{Offline: flags.Offline, Now: now, Root: root})
	if err != nil {
		_ = root.Close()
		return prepared{}, err
	}
	// Surface IR decode warnings (missing AGENTS.md, unreadable skill
	// assets, etc.) rather than dropping them silently — they are real
	// drift-guard / debugging signal.
	for _, w := range mat.Warnings {
		rc.Logger.Warn("ir decode warning", "code", w.Code, "message", w.Message, "path", w.Provenance.Path)
	}

	reg, err := adapter.DiscoverAdapters(ctx, adapter.DiscoverOptions{
		Workspace: m,
		Bundled:   bundledAdapters(),
	})
	if err != nil {
		_ = root.Close()
		return prepared{}, fmt.Errorf("discover adapters: %w", err)
	}

	req := engine.Request{
		Root:          root,
		WorkspacePath: ws.Root,
		Registry:      reg,
		Targets:       m.Targets,
		Nodes:         mat.Nodes,
		Skills:        mat.Skills,
		Commit:        mat.Commit,
		Options:       engine.Options{Now: func() time.Time { return now }, Logger: rc.Logger},
	}
	return prepared{
		Workspace: ws,
		Manifest:  m,
		Root:      root,
		Request:   req,
		Close:     func() { _ = root.Close() },
	}, nil
}

package engine

import (
	"context"
	"errors"
	"io/fs"
	"time"

	"github.com/agent-sync/agent-sync/internal/report"
	syncpkg "github.com/agent-sync/agent-sync/internal/sync"
)

// Sentinel errors callers branch on with errors.Is.
var (
	// ErrAdapterNotFound is returned when a manifest target has no
	// matching entry in the discovered registry.
	ErrAdapterNotFound = errors.New("engine: adapter not found for target")

	// ErrDrift is returned when a reserved prefix holds unmanaged
	// content and the prefix was not listed in Options.AdoptPrefixes.
	ErrDrift = errors.New("engine: reserved prefix has drift; adopt or resolve")

	// ErrEmitOpsMismatch is returned when an adapter's EmitResult.Ops
	// (full op envelopes) does not agree 1:1 with EmitResult.OpsPerformed
	// (the gated {kind, path} summary). The engine refuses to write a set
	// the runtime gates never vetted.
	ErrEmitOpsMismatch = errors.New("engine: emit ops do not match the op summary")
)

type targetStatus int

const (
	statusOK targetStatus = iota
	statusUnchanged
	statusBlocked
)

type statusCounts struct {
	written  int
	deleted  int
	warnings int
}

type statusResult struct {
	status   targetStatus
	counts   statusCounts
	paths    []string
	warnings []string
}

func fsModeOf(mode uint32) fs.FileMode { return fs.FileMode(mode) }

// resolvedTargets applies TargetsFilter (if any) to the manifest targets,
// preserving manifest order.
func resolvedTargets(all, filter []string) []string {
	if len(filter) == 0 {
		return all
	}
	want := make(map[string]bool, len(filter))
	for _, f := range filter {
		want[f] = true
	}
	var out []string
	for _, t := range all {
		if want[t] {
			out = append(out, t)
		}
	}
	return out
}

// Sync runs the full pipeline for every target and returns the report
// summary. Recovery runs first to drive any half-finished swap to a clean
// state. In atomic mode the run aborts on the first target failure; in
// best-effort mode failures are recorded and the run continues.
func Sync(ctx context.Context, req Request) (report.Summary, error) {
	if req.Root == nil {
		return report.Summary{}, errors.New("engine: request root is nil")
	}
	if req.Registry == nil {
		return report.Summary{}, errors.New("engine: request registry is nil")
	}
	opts := req.Options
	now := opts.now()
	log := opts.logger()

	// Recovery is idempotent and global; drive any half-finished swap to a
	// clean state before touching anything.
	if _, err := syncpkg.Recover(req.Root, "."); err != nil {
		return report.Summary{}, err
	}

	targets := resolvedTargets(req.Targets, opts.TargetsFilter)
	var reports []report.TargetReport
	abort := false

	for _, target := range targets {
		if abort {
			reports = append(reports, report.TargetReport{Target: target, Status: report.StatusSkipped})
			continue
		}
		start := opts.now()
		res, err := applyTarget(ctx, req, target, now)
		dur := opts.now().Sub(start).Milliseconds()
		if err != nil {
			log.Error("target sync failed", "target", target, "err", err)
			tr := report.TargetReport{
				Target:     target,
				Status:     report.StatusFailed,
				DurationMs: dur,
				Error:      err.Error(),
			}
			reports = append(reports, tr)
			if opts.mode() == report.ModeAtomic {
				abort = true
			}
			continue
		}
		reports = append(reports, toTargetReport(target, res, dur))
	}

	// Capability report is best-effort observability; failure to persist
	// it never fails the sync.
	if err := writeCapabilityReport(ctx, req, now); err != nil {
		log.Warn("capability report not written", "err", err)
	}

	summary := report.Summarize(req.WorkspacePath, req.Commit, now.UTC().Format(time.RFC3339), opts.mode(), reports)
	return summary, nil
}

// Plan runs the pipeline up to (but not including) staging and returns
// the per-target change set without mutating the workspace. It powers
// `validate`.
func Plan(ctx context.Context, req Request) (PlanResult, error) {
	if req.Root == nil {
		return PlanResult{}, errors.New("engine: request root is nil")
	}
	if req.Registry == nil {
		return PlanResult{}, errors.New("engine: request registry is nil")
	}
	opts := req.Options
	now := opts.now()

	targets := resolvedTargets(req.Targets, opts.TargetsFilter)
	out := PlanResult{WorkspacePath: req.WorkspacePath, Commit: req.Commit}

	for _, target := range targets {
		change := planTarget(ctx, req, target, now)
		if len(change.WouldCreate) > 0 || len(change.WouldUpdate) > 0 || len(change.WouldDelete) > 0 || len(change.OutOfBand) > 0 {
			out.DriftDetected = true
		}
		out.Targets = append(out.Targets, change)
	}
	return out, nil
}

func toTargetReport(target string, res statusResult, dur int64) report.TargetReport {
	st := report.StatusOK
	switch res.status {
	case statusUnchanged:
		st = report.StatusUnchanged
	case statusBlocked:
		st = report.StatusBlocked
	}
	return report.TargetReport{
		Target:     target,
		Status:     st,
		DurationMs: dur,
		Counts: report.Counts{
			Written:   res.counts.written,
			Deleted:   res.counts.deleted,
			Warnings:  res.counts.warnings,
			Unchanged: 0,
		},
		Paths: res.paths,
	}
}

// Package adapter is the runtime layer of Unit 8: subprocess and
// in-process orchestration that turns the wire types in
// internal/adapter/contract into runnable adapter sessions.
//
// The package owns:
//   - adapter.yaml manifest parsing (this file)
//   - adapter discovery (PATH + workspace-manifest + bundled)
//   - subprocess and in-process transports
//   - the lifecycle orchestrator (initialize → initialized → emit → shutdown)
//   - declared-outputs integrity gate enforcement
//
// The wire types live in internal/adapter/contract; this package depends
// on them but does not re-export them.
package adapter

import (
	"errors"
	"fmt"
	"os"
	"regexp"
	"strings"

	"github.com/goccy/go-yaml"

	"github.com/agent-sync/agent-sync/internal/manifest"
)

// MaxAdapterManifestBytes caps the on-disk size of an adapter.yaml.
// 1 MiB is generous: real manifests are well under 1 KiB, and the cap
// is there to defend against pathological or hostile files.
const MaxAdapterManifestBytes = 1 << 20

// ContractVersionV1 is the only contract_version this build of agent-sync
// recognizes. Future protocol versions land via Unit 8b under capability
// negotiation; the wire form itself stays at agent-sync/v1.
const ContractVersionV1 = "agent-sync/v1"

// AdapterManifest describes one adapter as declared by its on-disk
// adapter.yaml. The manifest sits next to the binary on PATH and
// supplies the runtime with the metadata it needs to spawn the adapter
// and route ops correctly.
type AdapterManifest struct {
	// Name is the adapter's identifier. Must be a single token of
	// [a-z0-9][a-z0-9-_]{0,63} — same shape as IR node ids. Used in
	// PATH lookups (agent-sync-adapter-<name>) and in the workspace
	// manifest's adapters: block.
	Name string `yaml:"name"`

	// Version is a free-form version string. Compared against by humans;
	// the runtime does not interpret it.
	Version string `yaml:"version,omitempty"`

	// ContractVersion is the wire-protocol version the adapter speaks.
	// Must equal ContractVersionV1; the runtime refuses to load adapters
	// declaring any other value.
	ContractVersion string `yaml:"contract_version"`

	// Command is the argv slice the runtime uses to spawn the adapter.
	// Must be non-empty. The first element is resolved via $PATH unless
	// it contains a path separator.
	Command []string `yaml:"command"`

	// ReservedPrefix is the path prefix (relative to the workspace root)
	// the adapter owns. The runtime uses this to detect nested-prefix
	// violations across adapters and to scope the declared-outputs gate.
	// Trailing slashes are stripped on load.
	ReservedPrefix string `yaml:"reserved_prefix,omitempty"`
}

// Manifest-level sentinel errors. Callers branch with errors.Is.
var (
	// ErrAdapterManifest is returned for any adapter.yaml problem the
	// caller hasn't already classified more specifically.
	ErrAdapterManifest = errors.New("adapter: invalid adapter.yaml")

	// ErrAdapterManifestTooLarge is returned when the file size exceeds
	// MaxAdapterManifestBytes.
	ErrAdapterManifestTooLarge = errors.New("adapter: adapter.yaml exceeds maximum size")

	// ErrAdapterManifestMissingContractVersion is returned when the
	// contract_version field is absent or empty.
	ErrAdapterManifestMissingContractVersion = errors.New("adapter: adapter.yaml missing contract_version")

	// ErrAdapterContractVersionUnsupported is returned when
	// contract_version is set but does not equal ContractVersionV1.
	ErrAdapterContractVersionUnsupported = errors.New("adapter: contract_version not supported by this build")

	// ErrAdapterManifestEmptyCommand is returned when command is missing
	// or an empty slice.
	ErrAdapterManifestEmptyCommand = errors.New("adapter: adapter.yaml command is empty")

	// ErrAdapterManifestInvalidName is returned when name fails the
	// adapter-id grammar.
	ErrAdapterManifestInvalidName = errors.New("adapter: adapter.yaml name does not match required pattern")

	// ErrAdapterManifestInvalidReservedPrefix is returned when
	// reserved_prefix is set but is not a clean, workspace-relative,
	// forward-slash path. Rejected shapes: absolute paths (POSIX or
	// Windows), Windows volume prefixes ("C:..."), backslashes (always
	// reserved on POSIX, ambiguous on Windows), or any segment equal
	// to ".." (workspace escape).
	ErrAdapterManifestInvalidReservedPrefix = errors.New("adapter: reserved_prefix must be a clean workspace-relative forward-slash path")
)

// adapterNamePattern enforces the same id grammar as IR nodes:
// leading alphanumeric, then up to 63 of [a-z0-9-_]. Total 1..64.
var adapterNamePattern = regexp.MustCompile(`\A[a-z0-9][a-z0-9_-]{0,63}\z`)

// LoadAdapterManifestFile reads adapter.yaml from disk and decodes it.
// File-size cap is enforced before the YAML parse so a hostile file
// cannot consume unbounded memory.
func LoadAdapterManifestFile(path string) (*AdapterManifest, error) {
	info, err := os.Stat(path)
	if err != nil {
		return nil, fmt.Errorf("adapter: stat adapter.yaml: %w", err)
	}
	if info.Size() > MaxAdapterManifestBytes {
		return nil, fmt.Errorf("%w: %d bytes > %d", ErrAdapterManifestTooLarge, info.Size(), MaxAdapterManifestBytes)
	}
	data, err := os.ReadFile(path)
	if err != nil {
		return nil, fmt.Errorf("adapter: read adapter.yaml: %w", err)
	}
	if len(data) > MaxAdapterManifestBytes {
		// Defense-in-depth: file could grow between stat and read.
		return nil, fmt.Errorf("%w: %d bytes > %d", ErrAdapterManifestTooLarge, len(data), MaxAdapterManifestBytes)
	}
	return LoadAdapterManifestBytes(data)
}

// LoadAdapterManifestBytes decodes a YAML byte slice and validates it.
// Strict mode: unknown non-x- fields are rejected; x-prefixed fields
// are accepted as forward-compatible extensions.
func LoadAdapterManifestBytes(src []byte) (*AdapterManifest, error) {
	if len(src) > MaxAdapterManifestBytes {
		return nil, fmt.Errorf("%w: %d bytes > %d", ErrAdapterManifestTooLarge, len(src), MaxAdapterManifestBytes)
	}
	var m AdapterManifest
	if err := yaml.UnmarshalWithOptions(
		src,
		&m,
		yaml.DisallowUnknownField(),
		yaml.AllowFieldPrefixes("x-"),
	); err != nil {
		return nil, fmt.Errorf("%w: %s", ErrAdapterManifest, yaml.FormatError(err, false, true))
	}
	if err := validateAdapterManifest(&m); err != nil {
		return nil, err
	}
	return &m, nil
}

// SyntheticAdapterManifest constructs the implicit manifest used when
// PATH discovery finds an agent-sync-adapter-<name> binary without a
// sibling adapter.yaml. Name must already be validated by the caller —
// adapter-id grammar is enforced via path matching upstream.
//
// binaryPath is the path the runtime should exec when spawning this
// adapter. Discovery passes the absolute path it resolved during
// directory scan (filepath.Join(dir, e.Name())) so spawn-time exec
// uses the exact binary discovery validated rather than re-resolving
// "agent-sync-adapter-<name>" through $PATH (TOCTOU: the second lookup
// could pick up a different binary). When binaryPath is empty the
// manifest falls back to the bare PATH-relative name; callers without
// a resolved location only get the kubectl-plugin convention.
func SyntheticAdapterManifest(name, binaryPath string) *AdapterManifest {
	cmd := binaryPath
	if cmd == "" {
		cmd = "agent-sync-adapter-" + name
	}
	return &AdapterManifest{
		Name:            name,
		ContractVersion: ContractVersionV1,
		Command:         []string{cmd},
	}
}

func validateAdapterManifest(m *AdapterManifest) error {
	if !adapterNamePattern.MatchString(m.Name) {
		return fmt.Errorf("%w: name=%q", ErrAdapterManifestInvalidName, m.Name)
	}
	if m.ContractVersion == "" {
		return ErrAdapterManifestMissingContractVersion
	}
	if m.ContractVersion != ContractVersionV1 {
		return fmt.Errorf("%w: %q (this build supports %q only)",
			ErrAdapterContractVersionUnsupported, m.ContractVersion, ContractVersionV1)
	}
	if len(m.Command) == 0 {
		return ErrAdapterManifestEmptyCommand
	}
	for i, arg := range m.Command {
		if arg == "" {
			return fmt.Errorf("%w: command[%d] is empty", ErrAdapterManifestEmptyCommand, i)
		}
	}
	cleaned, err := ValidateReservedPrefix(m.ReservedPrefix)
	if err != nil {
		return err
	}
	m.ReservedPrefix = cleaned
	return nil
}

// ValidateReservedPrefix is the canonical validator for reserved_prefix
// values on both adapter.yaml and the workspace manifest's
// adapters[].reserved_prefix. It is a thin wrapper that maps the
// shared manifest.ValidateReservedPrefix sentinel onto the
// adapter-package sentinel so callers in this package can branch on
// errors.Is(err, ErrAdapterManifestInvalidReservedPrefix).
func ValidateReservedPrefix(s string) (string, error) {
	cleaned, err := manifest.ValidateReservedPrefix(s)
	if err != nil {
		// Re-wrap with the adapter-package sentinel; preserve the
		// underlying detail string for diagnostics.
		return "", fmt.Errorf("%w: %s", ErrAdapterManifestInvalidReservedPrefix, errDetailAfterColon(err))
	}
	return cleaned, nil
}

// errDetailAfterColon strips the leading "manifest: ..." sentinel prefix
// from a wrapped error so the adapter-side message reads naturally
// after re-wrapping. Falls back to err.Error() when the format doesn't
// match the expected shape.
func errDetailAfterColon(err error) string {
	msg := err.Error()
	if i := strings.Index(msg, ": "); i >= 0 {
		return msg[i+2:]
	}
	return msg
}

