129	// absLogical returns filepath.Abs(p) without resolving symlinks. The
130	// path is cleaned so filepath.Dir walks behave predictably.
131	func absLogical(p string) (string, error) {
132		if p == "" {
133			return "", fmt.Errorf("empty path")
134		}
135		if filepath.IsAbs(p) {
136			return filepath.Clean(p), nil
137		}
138		wd, err := os.Getwd()
139		if err != nil {
140			return "", fmt.Errorf("getwd: %w", err)
141		}
142		return filepath.Clean(filepath.Join(wd, p)), nil
143	}
