145	// validateManifestFile checks whether path is a valid (regular) manifest.
146	// It uses Lstat first so that a dangling symlink is detected and reported
147	// as ErrManifestNotRegular rather than silently treated as "not found."
148	//
149	// Return values:
150	//   - (*Workspace, true, nil)  — path is a regular file (or a symlink to one);
151	//     ManifestPath is set, Root and LogicalCwd are left empty for the caller to fill.
152	//   - (nil, false, nil)        — path does not exist at all; caller continues walk.
153	//   - (nil, false, err)        — dangling symlink, non-regular file, or I/O error;
154	//     caller must propagate the error.
155	func validateManifestFile(path string) (*Workspace, bool, error) {
156		linfo, err := os.Lstat(path)
