170				return nil, false, fmt.Errorf("%w: %q is a dangling symlink", ErrManifestNotRegular, path)
171			}
172			if err != nil {
173				return nil, false, fmt.Errorf("workspace: stat %q: %w", path, err)
174			}
175			if !info.Mode().IsRegular() {
176				return nil, false, fmt.Errorf("%w: %q is a symlink to %s", ErrManifestNotRegular, path, modeLabel(info.Mode()))
177			}
178			// Symlink to a regular file is accepted.
179			return &Workspace{ManifestPath: path}, true, nil
180		}
181	
182		if !linfo.Mode().IsRegular() {
183			return nil, false, fmt.Errorf("%w: %q is %s", ErrManifestNotRegular, path, modeLabel(linfo.Mode()))
